// ---- THE GATE: this node makes the decision, not the LLM ----
const THRESHOLD = 0.78; // tune per embedding model

const message = $('Incoming Ticket (Webhook)').item.json.body.message;
const conversationId = $('Incoming Ticket (Webhook)').item.json.body.conversation_id;
const email = $('Incoming Ticket (Webhook)').item.json.body.customer_email;

// Postgres returns one item per matched row, each with a `similarity` score
const rows = $('Supabase · Vector Match').all().map(i => i.json);
const topSim = rows.length ? Number(rows[0].similarity) : 0;

// Classifier output (defensive: OpenAI node output shape varies by version)
let topic = 'other';
let isProtected = false;
try {
  const c = $('OpenAI · Classify Topic').item.json;
  const txt = c.message?.content ?? c.content ?? c.text ?? JSON.stringify(c);
  const parsed = typeof txt === 'string' ? JSON.parse(txt) : txt;
  topic = parsed.topic || 'other';
  isProtected = parsed.protected === true;
} catch (e) { /* fail safe: treat as non-protected, gate on confidence */ }

// TWO INDEPENDENT GATES. Auto-answer only if BOTH pass.
let decision, reason;
if (isProtected) {
  decision = 'escalate';
  reason = 'protected_topic:' + topic;           // never auto-answer, even at high confidence
} else if (topSim < THRESHOLD) {
  decision = 'escalate';
  reason = 'low_confidence:' + topSim.toFixed(2); // undocumented / weak match -> don't guess
} else {
  decision = 'answer';
  reason = 'auto_answer';
}

const sources = rows.slice(0, 3)
  .map(r => `[${r.title || 'source'}] ${r.content || ''}`)
  .join('\n---\n');

return [{ json: { message, conversationId, email, topic, protected: isProtected, topSim, decision, reason, sources } }];
